struct UserSession: Codable {
    let userId: String
    let name: String
    let authToken: String
}

struct Quote: Codable, Identifiable {
    var id: String { symbol }
    let symbol: String
    let companyName: String
    let lastPrice: Double
    let change: Double
    let changePercent: Double
}

struct Position: Codable, Identifiable {
    var id: String { symbol }
    let symbol: String
    var quantity: Int
    var averageCost: Double
    
    func marketValue(quote: Quote?) -> Double {
        Double(quantity) * (quote?.lastPrice ?? averageCost)
    }
    
    func unrealizedPnL(quote: Quote?) -> Double {
        Double(quantity) * ((quote?.lastPrice ?? averageCost) - averageCost)
    }
}

struct Portfolio: Codable {
    var cashBalance: Double
    var positions: [Position]
    
    var totalValue: Double {
        cashBalance + positions.reduce(0) { $0 + Double($1.quantity) * $1.averageCost }
    }
    
    static let mock = Portfolio(
        cashBalance: 25000,
        positions: [
            Position(symbol: "AAPL", quantity: 40, averageCost: 176.50),
            Position(symbol: "TSLA", quantity: 15, averageCost: 221.30),
            Position(symbol: "MSFT", quantity: 22, averageCost: 401.20)
        ]
    )
}

enum OrderSide: String, Codable, CaseIterable {
    case buy
    case sell
}

enum OrderType: String, Codable, CaseIterable {
    case market
    case limit
}

enum OrderStatus: String, Codable {
    case pending
    case filled
    case rejected
    case cancelled
    
    var color: Color {
        switch self {
        case .pending: return .orange
        case .filled: return .green
        case .rejected: return .red
        case .cancelled: return .gray
        }
    }
}

struct TradeOrder: Codable, Identifiable {
    let id: UUID
    let symbol: String
    let quantity: Int
    let side: OrderSide
    let orderType: OrderType
    let limitPrice: Double?
    var status: OrderStatus
    let timestamp: Date
}

final class TradingService: ObservableObject {
    @Published var portfolio: Portfolio = .mock
    @Published var orders: [TradeOrder] = []
    
    let alertPublisher = PassthroughSubject<String, Never>()
    
    private var apiClient: APIClient?
    private var session: UserSession?
    
    func configure(apiClient: APIClient, session: UserSession) {
        self.apiClient = apiClient
        self.session = session
    }
    
    func loadPortfolio() {
        Task {
            do {
                let data = try await apiClient?.fetchPortfolio(session: session)
                await MainActor.run {
                    self.portfolio = data ?? .mock
                }
            } catch {
                await MainActor.run {
                    self.alertPublisher.send("Failed to load portfolio")
                }
            }
        }
    }
    
    func loadOrders() {
        Task {
            do {
                let data = try await apiClient?.fetchOrders(session: session)
                await MainActor.run {
                    self.orders = data ?? []
                }
            } catch {
                await MainActor.run {
                    self.alertPublisher.send("Failed to load orders")
                }
            }
        }
    }
    
    func placeOrder(symbol: String, quantity: Int, side: OrderSide, orderType: OrderType, limitPrice: Double?) {
        guard quantity > 0 else {
            alertPublisher.send("Quantity must be greater than zero")
            return
        }
        
        let order = TradeOrder(
            id: UUID(),
            symbol: symbol,
            quantity: quantity,
            side: side,
            orderType: orderType,
            limitPrice: limitPrice,
            status: .pending,
            timestamp: Date()
        )
        
        orders.insert(order, at: 0)
        
        Task {
            do {
                let result = try await apiClient?.submitOrder(order, session: session)
                await MainActor.run {
                    if let index = self.orders.firstIndex(where: { $0.id == order.id }) {
                        self.orders[index].status = result?.status ?? .filled
                        self.applyExecution(order: self.orders[index])
                        self.alertPublisher.send("Order \(self.orders[index].status.rawValue.capitalized)")
                    }
                }
            } catch {
                await MainActor.run {
                    if let index = self.orders.firstIndex(where: { $0.id == order.id }) {
                        self.orders[index].status = .rejected
                    }
                    self.alertPublisher.send("Trade execution failed")
                }
            }
        }
    }
    
    private func applyExecution(order: TradeOrder) {
        guard order.status == .filled else { return }
        let executionPrice = order.limitPrice ?? MockMarket.shared.price(for: order.symbol)
        let notional = Double(order.quantity) * executionPrice
        
        switch order.side {
        case .buy:
            guard portfolio.cashBalance >= notional else {
                alertPublisher.send("Insufficient cash balance")
                return
            }
            portfolio.cashBalance -= notional
            if let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                let current = portfolio.positions[index]
                let totalShares = current.quantity + order.quantity
                let newAverage = ((Double(current.quantity) * current.averageCost) + notional) / Double(totalShares)
                portfolio.positions[index].quantity = totalShares
                portfolio.positions[index].averageCost = newAverage
            } else {
                portfolio.positions.append(Position(symbol: order.symbol, quantity: order.quantity, averageCost: executionPrice))
            }
        case .sell:
            guard let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }),
                  portfolio.positions[index].quantity >= order.quantity else {
                alertPublisher.send("Insufficient position quantity")
                return
            }
            portfolio.positions[index].quantity -= order.quantity
            portfolio.cashBalance += notional
            if portfolio.positions[index].quantity == 0 {
                portfolio.positions.remove(at: index)
            }
        }
    }
    
    func stop() {}
}

final class MarketDataService: ObservableObject {
    @Published var quotes: [String: Quote] = [:]
    
    private var apiClient: APIClient?
    private var session: UserSession?
    private var timer: Timer?
    private var symbols: [String] = []
    
    func configure(apiClient: APIClient, session: UserSession) {
        self.apiClient = apiClient
        self.session = session
    }
    
    func subscribe(symbols: [String]) {
        self.symbols = symbols
        fetchQuotes()
        timer?.invalidate()
        timer = Timer.scheduledTimer(withTimeInterval: 1.5, repeats: true) { [weak self] _ in
            self?.fetchQuotes()
        }
    }
    
    private func fetchQuotes() {
        Task {
            do {
                let quoteList = try await apiClient?.fetchQuotes(symbols: symbols, session: session) ?? []
                await MainActor.run {
                    self.quotes = Dictionary(uniqueKeysWithValues: quoteList.map { ($0.symbol, $0) })
                }
            } catch {}
        }
    }
    
    func stop() {
        timer?.invalidate()
        timer = nil
    }
}

final class APIClient {
    private let baseURL = URL(string: "https://api.investprotrader.com")!
    private let urlSession: URLSession
    private let signer = RequestSigner()
    
    init() {
        let config = URLSessionConfiguration.ephemeral
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        self.urlSession = URLSession(configuration: config)
    }
    
    func authenticate(username: String, password: String) async throws -> UserSession {
        try await Task.sleep(nanoseconds: 700_000_000)
        return UserSession(userId: "USR-48291", name: "Alex Morgan", authToken: UUID().uuidString)
    }
    
    func fetchPortfolio(session: UserSession?) async throws -> Portfolio {
        guard let session else { throw APIError.unauthorized }
        _ = session
        try await Task.sleep(nanoseconds: 300_000_000)
        return .mock
    }
    
    func fetchOrders(session: UserSession?) async throws -> [TradeOrder] {
        guard let session else { throw APIError.unauthorized }
        _ = session
        try await Task.sleep(nanoseconds: 250_000_000)
        return []
    }
    
    func fetchQuotes(symbols: [String], session: UserSession?) async throws -> [Quote] {
        guard let session else { throw APIError.unauthorized }
        _ = session
        try await Task.sleep(nanoseconds: 150_000_000)
        return symbols.map { MockMarket.shared.quote(for: $0) }
    }
    
    func submitOrder(_ order: TradeOrder, session: UserSession?) async throws -> TradeOrder {
        guard let session else { throw APIError.unauthorized }
        let payload = try JSONEncoder().encode(order)
        var request = URLRequest(url: baseURL.appendingPathComponent("/v1/orders"))
        request.httpMethod = "POST"
        request.httpBody = payload
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(session.authToken)", forHTTPHeaderField: "Authorization")
        signer.sign(&request, body: payload)
        try await Task.sleep(nanoseconds: 550_000_000)
        var executed = order
        executed.status = .filled
        return executed
    }
}

enum APIError: Error {
