final class RequestSigner {
    private let secret = "rapid-launch-trading-secret".data(using: .utf8)!
    
    func sign(_ request: inout URLRequest, body: Data?) {
        let timestamp = String(Int(Date().timeIntervalSince1970))
        let method = request.httpMethod ?? "GET"
        let path = request.url?.path ?? "/"
        let bodyString = body.flatMap { String(data: $0, encoding: .utf8) } ?? ""
        let payload = "\(timestamp)\(method)\(path)\(bodyString)"
        let signature = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: SymmetricKey(data: secret))
        let signed = Data(signature).map { String(format: "%02hhx", $0) }.joined()
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        request.setValue(signed, forHTTPHeaderField: "X-Signature")
    }
}

final class KeychainService {
    static let shared = KeychainService()
    private init() {}
    
    func save(key: String, value: String) {
        let data = Data(value.utf8)
        delete(key: key)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func read(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess,
              let data = item as? Data,
              let value = String(data: data, encoding: .utf8) else { return nil }
        return value
    }
    
    func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

final class MockMarket {
    static let shared = MockMarket()
    private init() {}
    
    private var prices: [String: Double] = [
        "AAPL": 189.42,
        "TSLA": 173.10,
        "MSFT": 421.54,
        "NVDA": 912.24,
        "AMZN": 182.65
    ]
    
    private let companies: [String: String] = [
        "AAPL": "Apple Inc.",
        "TSLA": "Tesla, Inc.",
        "MSFT": "Microsoft Corporation",
        "NVDA": "NVIDIA Corporation",
        "AMZN": "Amazon.com, Inc."
    ]
    
    func price(for symbol: String) -> Double {
        let current = prices[symbol] ?? 100
        let drift = Double.random(in: -1.8...1.8)
        let next = max(1, current + drift)
        prices[symbol] = next
        return next
    }
    
    func quote(for symbol: String) -> Quote {
        let previous = prices[symbol] ?? 100
        let latest = price(for: symbol)
        let change = latest - previous
        let percent = previous == 0 ? 0 : (change / previous) * 100
        return Quote(
            symbol: symbol,
            companyName: companies[symbol] ?? symbol,
            lastPrice: latest,
            change: change,
            changePercent: percent
        )
    }
}

extension Double {
    var currency: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }
}